// ============================================================
// Node 3: Parse Message (WAHA webhook format)
// Extracts sender chat, text/media metadata from WAHA `message` events.
// Uses normalized sender key to keep conversation state stable.
// ============================================================

const body = $input.first().json.body || $input.first().json;
const event = body?.event;
const payload = body?.payload || body;

if (event && event !== 'message') {
  return [{ json: { skip: true } }];
}

if (payload?.fromMe || payload?.source === 'api') {
  return [{ json: { skip: true } }];
}

let chatId = payload?.from || payload?.chatId || '';
chatId = String(chatId).replace('@s.whatsapp.net', '@c.us');

if (!chatId || chatId === 'status@broadcast' || chatId.endsWith('@g.us') || chatId.endsWith('@newsletter')) {
  return [{ json: { skip: true } }];
}

const rawSender = String(payload?.from || payload?.chatId || chatId || '');
const rawLocalPart = rawSender.split('@')[0] || '';
const normalizedDigits = rawLocalPart.replace(/\D/g, '');
const senderPhone = normalizedDigits || rawLocalPart;
const conversationKey = normalizedDigits || String(chatId).toLowerCase();

if (!senderPhone || !conversationKey) {
  return [{ json: { skip: true } }];
}

const messageId = payload?.id || '';
const media = payload?.media || null;
const mime = media?.mimetype || payload?.mimetype || '';

let messageType = 'unknown';
let messageText = payload?.body || '';
let mediaUrl = media?.url || payload?.mediaUrl || '';
let mediaMimeType = mime;
let mediaFileName = media?.filename || payload?.filename || '';

if (payload?.hasMedia || mediaUrl || mediaMimeType) {
  if (mediaMimeType.startsWith('image/')) {
    messageType = 'image';
    mediaFileName = mediaFileName || 'image.jpg';
  } else {
    messageType = 'document';
    mediaFileName = mediaFileName || 'document';
  }
} else if (messageText) {
  messageType = 'text';
}

return [{
  json: {
    skip: false,
    senderPhone,
    conversationKey,
    chatId,
    messageId,
    messageType,
    messageText,
    mediaUrl,
    mediaMimeType,
    mediaFileName,
    messageKey: { id: messageId, chatId },
    raw: body,
  }
}];

// WAHA WhatsApp quotation collection + handoff
const WAHA_API_URL = 'http://172.17.0.1:3002';
const WAHA_API_KEY = 'B6D711FCDE4D4FD5936544120E713976';
const WAHA_SESSION = 'default';
const BACKEND_API_URL = 'http://172.17.0.1:3001';
const ACME_TENANT_SLUG = 'acme';
const ACME_EMAIL = 'admin@acme.com';
const ACME_PASSWORD = 'admin123';

const input = $input.first().json;
if (input.skip) {
  return [{ json: { action: 'no_op' } }];
}

const {
  senderPhone, conversationKey, chatId, messageType, messageText,
  mediaUrl, mediaMimeType, mediaFileName
} = input;

const text = (messageText || '').trim();
const textLower = text.toLowerCase();


// File-based state storage (replaces staticData which is broken in n8n 2.x Task Runner)
const fs = require('fs');
const STATE_FILE = '/home/node/.n8n/whatsapp_conversations.json';

function loadConversations() {
  try {
    return JSON.parse(fs.readFileSync(STATE_FILE, 'utf8'));
  } catch (e) {
    return {};
  }
}

function saveConversations(convs) {
  fs.writeFileSync(STATE_FILE, JSON.stringify(convs), 'utf8');
}

const allConversations = loadConversations();
const senderStateKey = conversationKey || senderPhone;
if (!senderStateKey) {
  return [{ json: { action: 'no_op' } }];
}
if (!allConversations[senderStateKey]) allConversations[senderStateKey] = { state: 'new' };

const conv = allConversations[senderStateKey];
if (chatId) conv.chat_id = chatId;
const state = conv.state;

let action = 'no_op';
let payload = {};

switch (state) {
  case 'new': {
    action = 'send_message';
    payload = {
      to: senderPhone,
      text: 'Welcome! Would you like to generate a quotation?\n\nReply *1* for Yes\nReply *2* for No',
    };
    conv.state = 'awaiting_confirm';
    break;
  }
  case 'awaiting_confirm': {
    if (text === '1' || textLower === 'yes') {
      action = 'send_message';
      payload = {
        to: senderPhone,
        text: 'Please send your BOQ file.\n\nAccepted formats:\n- Excel (.xlsx)\n- PDF (.pdf)\n- Images (you can send multiple)',
      };
      conv.state = 'awaiting_boq';
    } else if (text === '2' || textLower === 'no') {
      action = 'send_message';
      payload = { to: senderPhone, text: 'No problem! Send me a message anytime to start.' };
      conv.state = 'new';
    } else {
      action = 'send_message';
      payload = { to: senderPhone, text: 'Please reply with a valid option:\n\nReply *1* for Yes\nReply *2* for No' };
    }
    break;
  }
  case 'awaiting_boq': {
    if (messageType === 'document') {
      const isXlsx = (mediaMimeType || '').includes('spreadsheet')
        || (mediaMimeType || '').includes('excel')
        || (mediaFileName || '').toLowerCase().endsWith('.xlsx')
        || (mediaFileName || '').toLowerCase().endsWith('.xls');
      const isPdf = (mediaMimeType || '') === 'application/pdf' || (mediaFileName || '').toLowerCase().endsWith('.pdf');
      if (isXlsx || isPdf) {
        conv.boq_media_type = isPdf ? 'pdf' : 'xlsx';
        conv.boq_media_url = mediaUrl || null;
        conv.boq_filename = mediaFileName || (isPdf ? 'boq.pdf' : 'boq.xlsx');
        conv.boq_mime_type = mediaMimeType || (isPdf ? 'application/pdf' : 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet');
        action = 'send_message';
        payload = { to: senderPhone, text: 'BOQ file received.\n\nNow please send your Specification file (PDF only).' };
        conv.state = 'awaiting_spec';
      } else {
        action = 'send_message';
        payload = { to: senderPhone, text: 'Unsupported file format. Please send an Excel (.xlsx) or PDF (.pdf) file.' };
      }
    } else if (messageType === 'image') {
      conv.boq_images = [{ media_url: mediaUrl || null, mime_type: mediaMimeType || 'image/jpeg', filename: mediaFileName || 'boq_image_1.jpg' }];
      conv.boq_media_type = 'images';
      action = 'send_message';
      payload = { to: senderPhone, text: 'Image received! Send more images or reply *done* when finished.' };
      conv.state = 'collecting_boq_images';
    } else {
      action = 'send_message';
      payload = { to: senderPhone, text: 'Please send a BOQ file (Excel, PDF, or images).' };
    }
    break;
  }
  case 'collecting_boq_images': {
    if (messageType === 'image') {
      if (!conv.boq_images) conv.boq_images = [];
      conv.boq_images.push({
        media_url: mediaUrl || null,
        mime_type: mediaMimeType || 'image/jpeg',
        filename: mediaFileName || ('boq_image_' + (conv.boq_images.length + 1) + '.jpg'),
      });
      action = 'send_message';
      payload = { to: senderPhone, text: String(conv.boq_images.length) + ' image(s) received. Send more or reply *done* when finished.' };
    } else if (textLower === 'done') {
      action = 'send_message';
      payload = { to: senderPhone, text: String((conv.boq_images || []).length) + ' BOQ image(s) saved.\n\nNow please send your Specification file (PDF only).' };
      conv.state = 'awaiting_spec';
    } else {
      action = 'send_message';
      payload = { to: senderPhone, text: 'Please send an image or reply *done* when finished.' };
    }
    break;
  }
  case 'awaiting_spec': {
    const isPdf = messageType === 'document' && (((mediaMimeType || '') === 'application/pdf') || (mediaFileName || '').toLowerCase().endsWith('.pdf'));
    if (isPdf) {
      conv.spec_media_url = mediaUrl || null;
      conv.spec_filename = mediaFileName || 'specification.pdf';
      conv.spec_mime_type = mediaMimeType || 'application/pdf';
      action = 'send_message';
      payload = { to: senderPhone, text: 'Spec file received.\n\nWould you like to provide client details?\n\nReply *1* for Yes\nReply *2* to Skip' };
      conv.state = 'awaiting_client_choice';
    } else {
      action = 'send_message';
      payload = { to: senderPhone, text: 'Please send a PDF file for the specification.' };
    }
    break;
  }
  case 'awaiting_client_choice': {
    if (text === '1' || textLower === 'yes') {
      action = 'send_message';
      payload = { to: senderPhone, text: 'Enter *client name*:' };
      conv.state = 'collecting_client_name';
    } else if (text === '2' || textLower === 'skip') {
      conv.client_data = {};
      action = 'send_message';
      payload = { to: senderPhone, text: 'Client details skipped.\n\nWould you like to provide project details?\n\nReply *1* for Yes\nReply *2* to Skip' };
      conv.state = 'awaiting_project_choice';
    } else {
      action = 'send_message';
      payload = { to: senderPhone, text: 'Please reply with a valid option:\n\nReply *1* for Yes\nReply *2* to Skip' };
    }
    break;
  }
  case 'collecting_client_name': {
    if (text) {
      conv.client_data = { name: text };
      action = 'send_message';
      payload = { to: senderPhone, text: 'Enter *company name*:' };
      conv.state = 'collecting_company_name';
    } else {
      action = 'send_message';
      payload = { to: senderPhone, text: 'Please enter a client name.' };
    }
    break;
  }
  case 'collecting_company_name': {
    if (text) {
      conv.client_data.company_name = text;
      action = 'send_message';
      payload = { to: senderPhone, text: 'Enter *email* (or reply *skip*):' };
      conv.state = 'collecting_client_email';
    } else {
      action = 'send_message';
      payload = { to: senderPhone, text: 'Please enter a company name.' };
    }
    break;
  }
  case 'collecting_client_email': {
    conv.client_data.email = (textLower === 'skip') ? null : (text || null);
    action = 'send_message';
    payload = { to: senderPhone, text: 'Enter *phone number* (or reply *skip*):' };
    conv.state = 'collecting_client_phone';
    break;
  }
  case 'collecting_client_phone': {
    conv.client_data.phone = (textLower === 'skip') ? null : (text || null);
    action = 'send_message';
    payload = { to: senderPhone, text: 'Enter *address* (or reply *skip*):' };
    conv.state = 'collecting_client_address';
    break;
  }
  case 'collecting_client_address': {
    conv.client_data.address = (textLower === 'skip') ? null : (text || null);
    action = 'send_message';
    payload = { to: senderPhone, text: 'Client details saved.\n\nWould you like to provide project details?\n\nReply *1* for Yes\nReply *2* to Skip' };
    conv.state = 'awaiting_project_choice';
    break;
  }
  case 'awaiting_project_choice': {
    if (text === '1' || textLower === 'yes') {
      action = 'send_message';
      payload = { to: senderPhone, text: 'Enter *project name*:' };
      conv.state = 'collecting_project_name';
    } else if (text === '2' || textLower === 'skip') {
      const today = new Date().toISOString().split('T')[0];
      conv.project_data = { project_name: 'WhatsApp Project ' + Date.now(), city: 'Riyadh', country: 'KSA', due_date: today };
      action = 'send_message';
      payload = { to: senderPhone, text: 'Project details skipped.\n\nSelect *service option*:\n*1* - Supply Only\n*2* - Supply & Install\n*3* - Supply, Install & Commission' };
      conv.state = 'collecting_config_service';
    } else {
      action = 'send_message';
      payload = { to: senderPhone, text: 'Please reply with a valid option:\n\nReply *1* for Yes\nReply *2* to Skip' };
    }
    break;
  }
  case 'collecting_project_name': {
    if (text) {
      conv.project_data = { project_name: text };
      action = 'send_message';
      payload = { to: senderPhone, text: 'Enter *city*:' };
      conv.state = 'collecting_project_city';
    } else {
      action = 'send_message';
      payload = { to: senderPhone, text: 'Please enter a project name.' };
    }
    break;
  }
  case 'collecting_project_city': {
    if (text) {
      conv.project_data.city = text;
      action = 'send_message';
      payload = { to: senderPhone, text: 'Enter *country* (or reply *skip* for KSA):' };
      conv.state = 'collecting_project_country';
    } else {
      action = 'send_message';
      payload = { to: senderPhone, text: 'Please enter a city.' };
    }
    break;
  }
  case 'collecting_project_country': {
    conv.project_data.country = (textLower === 'skip') ? 'KSA' : (text || 'KSA');
    action = 'send_message';
    payload = { to: senderPhone, text: 'Enter *due date* (YYYY-MM-DD):' };
    conv.state = 'collecting_project_due_date';
    break;
  }
  case 'collecting_project_due_date': {
    const datePattern = /^\d{4}-\d{2}-\d{2}$/;
    if (text && datePattern.test(text)) {
      conv.project_data.due_date = text;
      action = 'send_message';
      payload = { to: senderPhone, text: 'Project details saved.\n\nSelect *service option*:\n*1* - Supply Only\n*2* - Supply & Install\n*3* - Supply, Install & Commission' };
      conv.state = 'collecting_config_service';
    } else {
      action = 'send_message';
      payload = { to: senderPhone, text: 'Please enter a valid date in YYYY-MM-DD format (e.g. 2026-05-30):' };
    }
    break;
  }
  case 'collecting_config_service': {
    if (['1', '2', '3'].includes(text)) {
      conv.quotation_config = { service_option: parseInt(text, 10) };
      action = 'send_message';
      payload = { to: senderPhone, text: 'Enter *margin percent* (or reply *0*):' };
      conv.state = 'collecting_config_margin';
    } else {
      action = 'send_message';
      payload = { to: senderPhone, text: 'Please select 1, 2, or 3.' };
    }
    break;
  }
  case 'collecting_config_margin': {
    const margin = parseFloat(text);
    if (!Number.isNaN(margin)) {
      conv.quotation_config.margin_percent = margin;
      action = 'send_message';
      payload = { to: senderPhone, text: 'Enter *payment terms* (or reply *skip*):' };
      conv.state = 'collecting_config_payment';
    } else {
      action = 'send_message';
      payload = { to: senderPhone, text: 'Please enter a valid number for margin percent.' };
    }
    break;
  }
  case 'collecting_config_payment': {
    conv.quotation_config.payment_terms_text = (textLower === 'skip') ? null : (text || null);
    action = 'send_message';
    payload = { to: senderPhone, text: 'Enter *quotation subject* (or reply *skip*):' };
    conv.state = 'collecting_config_subject';
    break;
  }
  case 'collecting_config_subject': {
    conv.quotation_config.subject = (textLower === 'skip') ? null : (text || null);
    conv.state = 'executing';
    action = 'execute_pipeline';
    payload = {
      senderPhone,
      conversationKey: senderStateKey,
      chatId: conv.chat_id || chatId || (senderPhone + '@c.us'),
      conversation: JSON.parse(JSON.stringify(conv)),
      config: {
        WAHA_API_URL,
        WAHA_API_KEY,
        WAHA_SESSION,
        BACKEND_API_URL,
        ACME_TENANT_SLUG,
        ACME_EMAIL,
        ACME_PASSWORD,
      },
    };
    break;
  }
  case 'executing': {
    action = 'send_message';
    payload = { to: senderPhone, text: 'Your quotation is being generated. You will receive it here shortly.' };
    break;
  }
  default: {
    conv.state = 'awaiting_confirm';
    action = 'send_message';
    payload = { to: senderPhone, text: 'Welcome! Would you like to generate a quotation?\n\nReply *1* for Yes\nReply *2* for No' };
    break;
  }
}

let wahaBody = null;
let wahaUrl = '';
if (action === 'send_message') {
  const targetChatId = chatId || conv.chat_id || (payload.to + '@c.us');
  wahaUrl = WAHA_API_URL + '/api/sendText';
  wahaBody = { session: WAHA_SESSION, chatId: targetChatId, text: payload.text };
}

saveConversations(allConversations);

return [{ json: { action, payload, wahaBody, wahaUrl, config: { WAHA_API_URL, WAHA_API_KEY, WAHA_SESSION } } }];

const input = $input.first().json;
const payload = input.payload || {};
const senderPhone = payload.senderPhone;
const conversationKey = payload.conversationKey || senderPhone;
const chatId = payload.chatId;
const conv = payload.conversation || {};
const config = payload.config || {};

const WAHA_API_URL = config.WAHA_API_URL;
const WAHA_API_KEY = config.WAHA_API_KEY;
const WAHA_SESSION = config.WAHA_SESSION;
const BACKEND_API_URL = config.BACKEND_API_URL;
const ACME_TENANT_SLUG = config.ACME_TENANT_SLUG;
const ACME_EMAIL = config.ACME_EMAIL;
const ACME_PASSWORD = config.ACME_PASSWORD;

const httpRequest = this.helpers.httpRequest;

const apiRequest = async (opts) => {
  const req = {
    method: opts.method,
    url: opts.url,
    headers: opts.headers || {},
    timeout: 30000,
    json: true,
  };
  if (opts.body !== undefined) {
    req.body = opts.body;
    req.data = opts.body;
  }
  return await httpRequest(req);
};

const sendText = async (text) => {
  await apiRequest({
    method: 'POST',
    url: WAHA_API_URL + '/api/sendText',
    headers: { 'X-Api-Key': WAHA_API_KEY, 'Content-Type': 'application/json' },
    body: {
      session: WAHA_SESSION,
      chatId: chatId || conv.chat_id || (senderPhone + '@c.us'),
      text,
    },
  });
};

try {
  const login = await apiRequest({
    method: 'POST',
    url: BACKEND_API_URL + '/api/auth/login',
    headers: { 'Content-Type': 'application/json', 'x-tenant-slug': ACME_TENANT_SLUG },
    body: { email: ACME_EMAIL, password: ACME_PASSWORD },
  });
  const token = login && login.access_token;
  if (!token) throw new Error('Backend login failed: missing access token');

  const startResp = await apiRequest({
    method: 'POST',
    url: BACKEND_API_URL + '/api/integrations/whatsapp/quotation/start',
    headers: {
      Authorization: 'Bearer ' + token,
      'x-tenant-slug': ACME_TENANT_SLUG,
      'Content-Type': 'application/json',
    },
    body: {
      sender_phone: senderPhone,
      chat_id: chatId || conv.chat_id || (senderPhone + '@c.us'),
      boq_media_type: conv.boq_media_type,
      boq_media_url: conv.boq_media_url || null,
      boq_filename: conv.boq_filename || null,
      boq_mime_type: conv.boq_mime_type || null,
      boq_images: (conv.boq_images || []).map((x) => ({
        media_url: x.media_url || null,
        mime_type: x.mime_type || null,
        filename: x.filename || null,
      })),
      spec_media_url: conv.spec_media_url,
      spec_filename: conv.spec_filename || 'specification.pdf',
      client_data: conv.client_data || {},
      project_data: conv.project_data || {},
      quotation_config: conv.quotation_config || {},
      waha_api_key: WAHA_API_KEY,
    },
  });

  await sendText(
    'Your quotation is being generated.\n\nProject ID: ' +
      startResp.project_id +
      '\nWe will send the final result here shortly.'
  );
  return [{ json: { success: true, project_id: startResp.project_id, pipeline_run_id: startResp.pipeline_run_id } }];
} catch (error) {
  const fs = require('fs');
  try {
    const convs = JSON.parse(fs.readFileSync('/home/node/.n8n/whatsapp_conversations.json', 'utf8'));
    if (convs[conversationKey]) {
      convs[conversationKey] = { state: 'new' };
      fs.writeFileSync('/home/node/.n8n/whatsapp_conversations.json', JSON.stringify(convs), 'utf8');
    }
  } catch (e) {}
  await sendText(
    'Could not start quotation generation.\n\n' +
      (error.message || String(error)) +
      '\n\nPlease try again.'
  );
  return [{ json: { success: false, error: String(error && error.message ? error.message : error) } }];
}

const WAHA_API_URL = 'http://172.17.0.1:3002';
const WAHA_API_KEY = 'B6D711FCDE4D4FD5936544120E713976';
const WAHA_SESSION = 'default';
const EXPECTED_CALLBACK_TOKEN = 'ragm-pipeline-callback-2026';

const httpRequest = this.helpers.httpRequest;
const req = $input.first().json;
const headers = req.headers || {};
const body = req.body || req;

const providedToken =
  headers['x-callback-token'] ||
  headers['X-Callback-Token'] ||
  '';

if (EXPECTED_CALLBACK_TOKEN && providedToken !== EXPECTED_CALLBACK_TOKEN) {
  return [{ json: { ignored: true, reason: 'invalid_token' } }];
}

const replyInfo = body.platform_reply_info || {};
const senderPhone = replyInfo.sender_phone || body.sender_phone || null;
const chatId = replyInfo.chat_id || body.chat_id || (senderPhone ? senderPhone + '@c.us' : null);
if (!chatId) {
  return [{ json: { ignored: true, reason: 'missing_recipient' } }];
}

const sendText = async (text) => {
  await httpRequest({
    method: 'POST',
    url: WAHA_API_URL + '/api/sendText',
    headers: {
      'X-Api-Key': WAHA_API_KEY,
      'Content-Type': 'application/json',
    },
    json: true,
    body: { session: WAHA_SESSION, chatId, text },
    data: { session: WAHA_SESSION, chatId, text },
    timeout: 15000,
  });
};

if (body.status === 'completed') {
  const downloadUrl = body.download_url || null;
  const fileName = body.file_name || 'quotation.docx';
  if (downloadUrl) {
    await sendText('Your quotation is ready.\n\nFile: ' + fileName + '\nDownload: ' + downloadUrl);
  } else {
    await sendText('Pipeline completed for project ' + body.project_id + ', but no download link was provided.');
  }
} else if (body.status === 'failed') {
  await sendText(
    'Quotation generation failed.\nProject: ' +
      body.project_id +
      '\nStep: ' +
      (body.error_step || 'unknown') +
      '\nError: ' +
      (body.error_message || 'unknown error')
  );
}

if (senderPhone) {
  const fs = require('fs');
  try {
    const convs = JSON.parse(fs.readFileSync('/home/node/.n8n/whatsapp_conversations.json', 'utf8'));
    convs[senderPhone] = { state: 'new' };
    fs.writeFileSync('/home/node/.n8n/whatsapp_conversations.json', JSON.stringify(convs), 'utf8');
  } catch (e) {
    const convs = {};
    convs[senderPhone] = { state: 'new' };
    fs.writeFileSync('/home/node/.n8n/whatsapp_conversations.json', JSON.stringify(convs), 'utf8');
  }
}

return [{ json: { ok: true } }];
